  6→import { authClient } from "./lib/auth-client";
  7→import { AcceptInvitationPage } from "./pages/AcceptInvitationPage";
  8→import { CreateOrgPage } from "./pages/dashboard/CreateOrgPage";
  9→import { DeveloperDetailPage } from "./pages/dashboard/DeveloperDetailPage";
 10→import { DevelopersListPage } from "./pages/dashboard/DevelopersListPage";
 11→import { ErrorsPage } from "./pages/dashboard/ErrorsPage";
 12→import { LearningsPage } from "./pages/dashboard/LearningsPage";
 13→import { OrganizationPage } from "./pages/dashboard/OrganizationPage";
 14→import { OverviewPage } from "./pages/dashboard/OverviewPage";
 15→import { ProfilePage } from "./pages/dashboard/ProfilePage";
 16→import { ProjectDetailPage } from "./pages/dashboard/ProjectDetailPage";
 17→import { ProjectsListPage } from "./pages/dashboard/ProjectsListPage";
 18→import { ROIPage } from "./pages/dashboard/ROIPage";
 19→import { SessionDetailPage } from "./pages/dashboard/SessionDetailPage";
 20→import { SessionsListPage } from "./pages/dashboard/SessionsListPage";
 21→
 22→type Page = "login" | "signup";
 23→
 24→function getCliParams(): { cliCallback: string; state: string } | null {
 25→	const params = new URLSearchParams(window.location.search);
 26→	const cliCallback = params.get("cli_callback");
 27→	const state = params.get("state");
 28→	if (!cliCallback || !state) return null;
 29→	try {
 30→		const url = new URL(cliCallback);
 31→		if (url.hostname !== "127.0.0.1") return null;
 32→	} catch {
 33→		return null;
 34→	}
 35→	return { cliCallback, state };
 36→}
 37→
 38→function App() {
 39→	const { data: session, isPending } = authClient.useSession();
 40→	const [page, setPage] = useState<Page>("login");
 41→	const [cliRedirecting, setCliRedirecting] = useState(false);
 42→	const cliParams = getCliParams();
 43→
 44→	useEffect(() => {
 45→		if (!session || !cliParams || cliRedirecting) return;
 46→		setCliRedirecting(true);
 47→
 48→		fetch("/api/cli-token", { credentials: "include" })
 49→			.then((res) => res.json())
 50→			.then((data: { token: string }) => {
 51→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 52→				window.location.href = redirectUrl;
 53→			});
 54→	}, [session, cliParams, cliRedirecting]);
 55→
 56→	if (isPending) {
 57→		return (
 58→			<div className="flex min-h-screen items-center justify-center">
 59→				<p className="text-muted-foreground">Loading...</p>
 60→			</div>
 61→		);
 62→	}
 63→
 64→	if (cliRedirecting) {
 65→		return (
 66→			<div className="flex min-h-screen items-center justify-center">
 67→				<p className="text-muted-foreground">Completing CLI login...</p>
 68→			</div>
 69→		);
 70→	}
 71→
 72→	if (!session) {
 73→		return (
 74→			<div className="flex min-h-screen items-center justify-center">
 75→				{page === "login" ? (
 76→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 77→				) : (
 78→					<SignupForm onSwitchToLogin={() => setPage("login")} />
 79→				)}
 80→			</div>
 81→		);
 82→	}
 83→
 84→	return (
 85→		<Routes>
 86→			<Route path="/" element={<Navigate to="/dashboard" replace />} />
 87→			<Route
 88→				path="/invitation/:invitationId"
 89→				element={<AcceptInvitationPage />}
 90→			/>
 91→			<Route path="/dashboard" element={<DashboardLayout />}>
 92→				<Route index element={<OverviewPage />} />
 93→				<Route path="developers" element={<DevelopersListPage />} />
 94→				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
 95→				<Route path="projects" element={<ProjectsListPage />} />
 96→				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
 97→				<Route path="sessions" element={<SessionsListPage />} />
 98→				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
 99→				<Route path="roi" element={<ROIPage />} />
100→				<Route path="errors" element={<ErrorsPage />} />
101→				<Route path="learnings" element={<LearningsPage />} />
102→				<Route path="profile" element={<ProfilePage />} />
103→				<Route path="organization" element={<OrganizationPage />} />
104→				<Route path="organization/new" element={<CreateOrgPage />} />
105→			</Route>
106→			<Route path="*" element={<Navigate to="/dashboard" replace />} />
107→		</Routes>
108→	);
109→}
110→
111→export default App;
