										<div className="flex items-center gap-3">
											<Icon className="h-4 w-4 text-muted" />
											<span className="text-sm font-medium text-subheading">
												{provider.label}
											</span>
										</div>
										{isLinked ? (
											<span className="text-xs font-medium text-status-success-icon">
												Connected
											</span>
